parameters.jsCode:
const data = items[0].json;
const messages = data.output[0].content[0].text.messages;

const fields = [];
for (let i = 0; i < messages.length; i++) {
  if (messages[i]?.field_value) {
    fields.push({
      field_name: "AI > Answer " + (i + 1),
      field_value: messages[i].field_value
    });
  }
}

return [
  {
    json: {
      subscriber_id: $('Webhook').first().json.body.id,
      fields: fields
    }
  }
];
